import { type PaymentMethod } from '@bigcommerce/checkout-sdk';
import React, { type ComponentType, lazy, Suspense } from 'react';

import { PaymentFormProvider, type PaymentFormValues } from '@bigcommerce/checkout/contexts';
import { withLanguage, type WithLanguageProps } from '@bigcommerce/checkout/locale';
import { LazyContainer } from '@bigcommerce/checkout/ui';

import { withCheckout, type WithCheckoutProps } from '../../checkout';
import { connectFormik, type WithFormikProps } from '../../common/form';
import createPaymentFormService from '../createPaymentFormService';
import resolvePaymentMethod from '../resolvePaymentMethod';
import withForm, { type WithFormProps } from '../withForm';
import withPayment, { type WithPaymentProps } from '../withPayment';

const PaymentMethodV1 = lazy(
    () => import(/* webpackChunkName: "payment-method-v1" */ './PaymentMethod'),
);

export interface PaymentMethodProps {
    method: PaymentMethod;
    isEmbedded?: boolean;
    isUsingMultiShipping?: boolean;
    onUnhandledError(error: Error): void;
}

const PaymentMethodContainer: ComponentType<
    PaymentMethodProps &
        WithCheckoutProps &
        WithLanguageProps &
        WithPaymentProps &
        WithFormProps &
        WithFormikProps<PaymentFormValues>
> = ({
    formik: formikContext,
    checkoutService,
    checkoutState,
    disableSubmit,
    hidePaymentSubmitButton,
    isEmbedded,
    isSubmitted,
    isUsingMultiShipping,
    language,
    method,
    onUnhandledError,
    setSubmit,
    setSubmitted,
    setValidationSchema,
}) => {
    const formContext = {
        isSubmitted,
        setSubmitted,
    };

    const paymentContext = {
        disableSubmit,
        hidePaymentSubmitButton,
        setSubmit,
        setValidationSchema,
    };

    const config = checkoutState.data.getConfig();
    const ResolvedPaymentMethod = resolvePaymentMethod(
        {
            id: method.id,
            gateway: method.gateway,
            type: method.type,
        },
        config?.checkoutSettings,
    );

    const debugBanner = (
        <div style={{background: 'orange', padding: '5px', fontSize: '12px'}}>
            RESOLVE: id={method.id} gateway={method.gateway} type={method.type} method={method.method} found={String(!!ResolvedPaymentMethod)}
            <pre style={{fontSize: '10px', whiteSpace: 'pre-wrap', wordBreak: 'break-all'}}>{JSON.stringify(method, null, 2)}</pre>
        </div>
    );

    if (!ResolvedPaymentMethod) {
        return (
            <>
                {debugBanner}
                <LazyContainer>
                    <PaymentMethodV1
                        isEmbedded={isEmbedded}
                        isUsingMultiShipping={isUsingMultiShipping}
                        method={method}
                        onUnhandledError={onUnhandledError}
                    />
                </LazyContainer>
            </>
        );
    }

    const paymentForm = createPaymentFormService(formikContext, formContext, paymentContext);

    return (
        <>
        {debugBanner}
        <PaymentFormProvider paymentForm={paymentForm}>
            <Suspense>
                <ResolvedPaymentMethod
                    checkoutService={checkoutService}
                    checkoutState={checkoutState}
                    language={language}
                    method={method}
                    onUnhandledError={onUnhandledError}
                    paymentForm={paymentForm}
                />
            </Suspense>
        </PaymentFormProvider>
        </>
    );
};

export default withCheckout((props) => props)(
    withLanguage(withPayment(withForm(connectFormik(PaymentMethodContainer)))),
) as ComponentType<PaymentMethodProps>;








